import threading
from typing import Any, Dict, Set, Optional, ContextManager
from collections import OrderedDict

class InMemoryStore:
    """An in-memory key-value store with support for transactions, TTL, LRU eviction, and thread-safety."""

    def __init__(self, max_size: int = 0, ttl: Optional[int] = None, lazy: bool = False):
        """
        Initialize the in-memory store.

        Args:
            max_size: Maximum number of key-value pairs to store (0 for no limit).
            ttl: Time-to-Live in seconds. If None, use active TTL.
            lazy: Use lazy expiration (check TTL on access).
        """
        self.max_size = max_size
        self.ttl = ttl
        self.lazy = lazy
        self._lock = threading.Lock()
        self.items: Dict[str, Any] = {}
        self.ttl_cache: Dict[str, int] = {}
        self.timestamp = 0
        self.active_keys: Set[str] = set()
        self._transactions: List[Transaction] = []
        self._current_transaction: Optional[Transaction] = None
        self._cache_order = OrderedDict()

    def __enter__(self) -> 'InMemoryStore':
        """Context manager for transactions."""
        if self._current_transaction is None:
            self._current_transaction = Transaction()
            self._transactions.append(self._current_transaction)
        return self

    def __exit__(self, exc_type: Optional[Type[BaseException]], exc_val: Optional[BaseException], exc_tb: Optional[Traceback]) -> None:
        """Commit or rollback the current transaction."""
        if self._current_transaction is not None:
            if exc_type is not None:
                self._current_transaction.rollback()
            else:
                self._current_transaction.commit()
            self._current_transaction = None
        else:
            pass

    def get(self, key: str, default: Optional[Any] = None) -> Any:
        """Retrieve a value by key."""
        with self._lock:
            if key in self.items:
                if self.lazy and self.ttl_cache.get(key) is None:
                    return self.items[key]
                elif self.ttl is not None and self.ttl_cache.get(key) >= self.timestamp:
                    return None
                return self.items[key]
            return default

    def set(self, key: str, value: Any, ttl: Optional[int] = None) -> None:
        """Set or update a value with optional TTL."""
        with self._lock:
            if key in self.ttl_cache:
                if ttl is None:
                    self.ttl_cache[key] = threading.current_time()
                else:
                    self.ttl_cache[key] += ttl
            else:
                self.items[key] = value
                self.ttl_cache[key] = threading.current_time() if ttl is None else ttl
                self.timestamp = max(self.timestamp, threading.current_time())
                self.active_keys.add(key)
                if self.max_size > 0 and len(self.items) > self.max_size:
                    self._lru_evict()

    def delete(self, key: str) -> None:
        """Delete a key-value pair."""
        with self._lock:
            if key in self.items:
                if self.lazy and self.ttl_cache.get(key) is None:
                    del self.items[key]
                elif self.ttl is not None and self.ttl_cache.get(key) >= self.timestamp:
                    del self.items[key]
                else:
                    del self.ttl_cache[key]
                    if self.max_size > 0 and len(self.items) > self.max_size:
                        self._lru_evict()

    def ttl_delete(self, key: str) -> None:
        """Delete a key-value pair with TTL expiration."""
        with self._lock:
            if key in self.ttl_cache:
                if self.ttl is not None:
                    self.ttl_cache[key] += self.ttl
                else:
                    del self.ttl_cache[key]

    def _lru_evict(self) -> None:
        """Evict the least recently used item."""
        if len(self.items) > self.max_size:
            for key in list(self.active_keys):
                if self.timestamp > threading.current_time() - self.ttl_cache.get(key, 0):
                    self._cache_order.move_to_end(key, last=True)
                    break
            else:
                self._cache_order.move_to_end(self._cache_order.popitem(last=False), last=True)
            self.active_keys.discard(self._cache_order.popitem(last=True)[0])
            self.items.popitem(last=True)

    def begin_transaction(self) -> None:
        """Start a new transaction."""
        with self._lock:
            if self._current_transaction is None:
                self._current_transaction = Transaction()

    def commit_transaction(self) -> None:
        """Commit the current transaction."""
        with self._lock:
            if self._current_transaction is not None:
                self._transactions[-1].session_id = threading.get_ident()
                self._current_transaction = None

    def rollback_transaction(self) -> None:
        """Rollback the current transaction."""
        with self._lock:
            if self._current_transaction is not None:
                self._current_transaction.session_id = None
                self._current_transaction = None

    def save_state(self) -> None:
        """Save the current state of the store."""
